STR_ID_4201		 = 4201		-- EVE experienced sensations presumably equivalent to the Human term 'anger'.
STR_ID_4202		 = 4202		-- EVE slapped the red-haired boy -- an illogical and regrettable response.
STR_ID_4203		 = 4203		-- The pain cannot be undone and the red-haired boy's face somehow turned red.
STR_ID_4204		 = 4204		-- Evidence shows that many Humans are suffering at the hands of revived Nasods.
STR_ID_4205		 = 4205		-- (Accessing Archived Data)\nNasods also suffered from Humans in the late era. They faced termination if They did not follow all the rules.
STR_ID_4206		 = 4206		-- EVE does not seek revenge... only seeks to unite with kindred beings.
STR_ID_4207		 = 4207		-- Although such motivation is akin to Human emotion, it is hardly inappropriate for a Nasod with advanced knowledge to activate the desire for friends.
STR_ID_4208		 = 4208		-- EVE is determined to resurrect the Nasod race, and this is now her prime objective.
STR_ID_4209		 = 4209		-- It is not an emotional imperative, but a rational response to current circumstances.
STR_ID_4210		 = 4210		-- Characteristics observed in previous statement -- further investigation is required.
STR_ID_4211		 = 4211		-- In any case, EVE, as the last Nasod will remain alone again.
