STR_ID_4660		 = 4660		-- Wow, can I really ask you anything? Hoho! 
STR_ID_4661		 = 4661		-- Say hello to Lenphad! 
STR_ID_4662		 = 4662		-- I am Noel the Star, wandering the world. Want to hear me sing? 
STR_ID_4663		 = 4663		-- Traveling? This is no time for traveling. Hahaha! 
STR_ID_4664		 = 4664		-- 'Goodbye' isn't forever. I'll see you again. Hahaha! 
STR_ID_4665		 = 4665		-- For a man,  what's important is who he is inside… Don't judge a man by his looks. 
STR_ID_4666		 = 4666		-- I was once the famous alchemist of Velder, you know.   
STR_ID_4667		 = 4667		-- Looking for something?... 
STR_ID_4668		 = 4668		-- If I had a human body... I would've done it myself… Sorry to have to ask you. 
