STR_ID_18457		 = 18457		-- That's a cool name pong! You're a genius pong!
STR_ID_18458		 = 18458		-- To tell you the truth…Disfrozen Portal does not fully work yet Pong.. After the energy fuses, it overloads and stops repeatedly in irregular ways Pong..
