STR_ID_24623		 = 24623		-- 태양과 달이 하나가 되는 때, 엘의 기운을 풍요롭고 비옥하게 하는 날이 랍니다~
STR_ID_24624		 = 24624		-- 모두가 풍요로운 공존의 축제를 맞이해서 축제기간 동안 매일 매일 유용한 아이템을 드려요~
STR_ID_24625		 = 24625		-- 안녕하세요, 아리엘이에요~
STR_ID_24626		 = 24626		-- 이번 공존의 축제를 맞이하여 모험가 여러분들 위한 특별한 선물을 준비했어요~
STR_ID_24627		 = 24627		-- 선물을 받으세요, 모험가님! 
STR_ID_24628		 = 24628		-- 앞으로도 모험이 가득한 엘리오스를 마음껏 탐험해 주세요!
STR_ID_24629		 = 24629		-- 마족치고는 너무 쉬운걸~?\n좀 더 강한 상대는 없는거야!?
STR_ID_24630		 = 24630		-- 카리스… 베히모스를 이렇게 만들다니! 용서하지 않겠어!
STR_ID_24631		 = 24631		-- 신녀님은 무사히 되찾았지만, 카리스를 놓치다니!\n어서 빨리 뒤쫒아야겠어!
STR_ID_24632		 = 24632		-- 헤헷, 이정도 마족따윈 상대도 안되지!\n전부 덤비라구, 얼마든지 상대해주겠어!
STR_ID_24633		 = 24633		-- 설마 베히모스를 조종 할 줄이야…\n이건 내 마력을 전부 쏟아부어도 불가능한 일이라구!
STR_ID_24634		 = 24634		-- 훗-! 카리스도 별거아니네-\n내 마법이라면 문제없어!
STR_ID_24635		 = 24635		-- 내 마법으로도 이 정도 규모의 배를 띄우는건 힘들어...\n하지만, 구속장치 정도라면 어떻게 해볼수도 있다구!
STR_ID_24636		 = 24636		-- 베히모스 중심부에서 강대하지만 불길한 마력이 느껴져…\n이 불길한 기운은 뭐지…?
STR_ID_24637		 = 24637		-- 고대 유물을 해하려들다니, 마족들은 정말 몰상식하군요!
STR_ID_24638		 = 24638		-- 카리스가 도주했어요… \n무언가 좋지 않은 느낌이 들어요… 어서 카리스를 막아야겠어요.
STR_ID_24639		 = 24639		-- 더 이상 지체 할 시간은 없어요!\n베히모스 내부로 카리스를 쫒아야해요!
STR_ID_24640		 = 24640		-- 아… 이 엘의 기운은…!!\n어째서 이런 느낌이 드는거죠? 도대체 무슨 일이 있길래!
STR_ID_24641		 = 24641		-- 발판이 불안정한 곳에서 전투할때는 나름의 대처법이 있지…\n이 정도 흔들림은 아무것도 아니야.
STR_ID_24642		 = 24642		-- 마족들이 군집을 이루어 비공정을 공격해오다니.\n좀 더 확실한 전술로 전투에 임할 필요가 있겠군.
STR_ID_24643		 = 24643		-- 비…공정이라… 지금은 신경쓸때가 아니야.\n쓸대없는 생각은 집어치우고 카리스를 쫒아야겠어.
STR_ID_24644		 = 24644		-- 마족이란것도 별거아니군.\n하지만 밑에서 올라오는 이 위압감은 도대체…
STR_ID_24645		 = 24645		-- 이렇게 신비한 비공정에 이런 짓을 하다니\n마족은 정말 기계에 대한 미학이 없군요.
STR_ID_24646		 = 24646		-- 모두 조심하십시요, 파손된 부위가 많습니다.\n분석완료! 수리가 필요한 위치을 알아내었습니다.
STR_ID_24647		 = 24647		-- 구속장치, 순수하게 기술력만으로 만들어진 것이 아니군요.\n알 수 없는 제작방식입니다, 흥미롭군요.
STR_ID_24648		 = 24648		-- 삐빗-! 무언가 엄청난 힘이 감지되었습니다!\n이 거대한 생명체의 중심기관 입니다만, 명확하지 않군요.
STR_ID_24649		 = 24649		-- 베히모스의 주요기관을 파괴해야해요!\n모두들 어서 카리스를 쫒아가죠!
STR_ID_24650		 = 24650		-- 위험한 구간이 많아요!\n아이샤, 레나, 아라 누나 조심하세요!
STR_ID_24651		 = 24651		-- 이 힘은… 제 수호석의 기운과 매우 비슷하군요.\n어쩌면 제 수호석의 힘을 더 강화시킬 수 있을 지도...
STR_ID_24652		 = 24652		-- 카리스가 베히모스의 몸 속으로 도주했어요!\n어떤 함정이 있을지 모르지만 모두를 위해 카리스를 막아야 해요!
STR_ID_24653		 = 24653		-- 이 생물체 중심에서 수상한 기운이 느껴집니다.\n무언가 오라버니의 느낌과 비슷한…
